$sourcePath = 'C:\Source'`n$destinationPath = 'C:\Destination'`n$logFile = 'C:\log.txt'`n$timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'`nfunction Log-Message {`n    param([string]$message)`n    $logEntry = "$timestamp - $message"`n    Add-Content -Path $logFile -Value $logEntry`n}`nfunction Copy-Files {`n    param([string]$source, [string]$destination)`n    Get-ChildItem -Path $source -Recurse | ForEach-Object {`n        $targetPath = Join-Path -Path $destination -ChildPath $_.FullName.Substring($source.Length)`n        if (-not (Test-Path -Path (Split-Path -Path $targetPath -Parent))) {`n            New-Item -ItemType Directory -Path (Split-Path -Path $targetPath -Parent)`n        }`n        Copy-Item -Path $_.FullName -Destination $targetPath -Force`n        Log-Message "Copied: $_.FullName to $targetPath"`n    }`n}`nfunction Delete-OldFiles {`n    param([string]$path, [int]$days)`n    $cutoffDate = (Get-Date).AddDays(-$days)`n    Get-ChildItem -Path $path -Recurse | Where-Object {`n        $_.LastWriteTime -lt $cutoffDate`n    } | ForEach-Object {`n        Remove-Item -Path $_.FullName -Force`n        Log-Message "Deleted: $_.FullName"`n    }`n}`nCopy-Files -source $sourcePath -destination $destinationPath`nDelete-OldFiles -path $sourcePath -days 30`nLog-Message "Utility execution completed."
